void ui_event_preset_changed(lv_event_t * e)
{
	// Your code here
	int preset_idx = lv_dropdown_get_selected(ui_PresetSelect);
	g_display_mgr.PresetIdx = preset_idx;

	lv_obj_t* boxes[10] = {
		ui_Select_Box1, ui_Select_Box2, ui_Select_Box3, ui_Select_Box4, ui_Select_Box5,
		ui_Select_Box6, ui_Select_Box7, ui_Select_Box8, ui_Select_Box9, ui_Select_Box10
	};

	for (int i = 0; i < 10; i++) {
		int isChannel2 = (i >= 5);
		int internal_slot = isChannel2 ? (i - 5) : i;

		AudioChannel_t* live_channel = isChannel2 ? &Channel2 : &Channel1;

		Effect_t* preset_effect = isChannel2
			? &presets[preset_idx].Channel2.chain[internal_slot]
			: &presets[preset_idx].Channel1.chain[internal_slot];

		int effect_type = 0;

		if (preset_effect->process != NULL && preset_effect->process != bypassProcess) {
		    for (int j = 0; j < NUM_EFFECTS; j++) {
		        if (preset_effect->process == effectList[j].process) {
		            effect_type = j;
		            break;
		        }
		    }
		}

		g_display_mgr.effectsIdx[i] = effect_type;
		if (effect_type > 0 && effect_type < NUM_EFFECTS) {

		    if (live_channel->chain[internal_slot].process != preset_effect->process) {
		        live_channel->chain[internal_slot].process = preset_effect->process;
		        live_channel->chain[internal_slot].enabled = true;
		        lv_memset(live_channel->chain[internal_slot].state, 0, sizeof(live_channel->chain[internal_slot].state));
		    }

		    lv_memcpy(live_channel->chain[internal_slot].params, preset_effect->params, sizeof(live_channel->chain[internal_slot].params));
		}
		else {
		    live_channel->chain[internal_slot].process = preset_effect->process; // Keeps bypassProcess safely
		    live_channel->chain[internal_slot].enabled = false;
		    lv_memcpy(live_channel->chain[internal_slot].params, preset_effect->params, sizeof(live_channel->chain[internal_slot].params));
		}

		if (boxes[i] != NULL) {
			lv_obj_t* box_label = lv_obj_get_child(boxes[i], 0);
			if (box_label != NULL) {
				lv_label_set_text(box_label, effect_db[effect_type].abbreviation);
			}
		}
	}

	Channel1.chainLen = MAX_EFFECT_COUNT;
	Channel2.chainLen = MAX_EFFECT_COUNT;
	g_display_mgr.presetChanged = 1;
}

void uiUpdatePedalScreen(lv_event_t * e)
{
	// Your code here
	char idxBuf[8];
	lv_snprintf(idxBuf, sizeof(idxBuf), "%02d:", g_display_mgr.activeSlotIdx + 1);
	lv_label_set_text(ui_BGEffect, idxBuf);

	AudioChannel_t* active_channel = (g_display_mgr.activeSlotIdx < 5) ? &Channel1 : &Channel2;
	int internal_slot_idx = (g_display_mgr.activeSlotIdx < 5) ? g_display_mgr.activeSlotIdx : g_display_mgr.activeSlotIdx - 5;

	Effect_t* active_effect = &active_channel->chain[internal_slot_idx];

	int effect_type = 0;
	if (active_effect->process != NULL && active_effect->process != bypassProcess) {
		for (int j = 0; j < NUM_EFFECTS; j++) {
			if (active_effect->process == effectList[j].process) {
				effect_type = j;
				break;
			}
		}
	}

	EffectMetadata_t* md = &effect_db[effect_type];

	lv_dropdown_set_selected(ui_PedalSel1, effect_type);
	lv_label_set_text(ui_PedalDescripton, md->description);

	lv_obj_t* arcs[6] = { ui_Parameter, ui_Parameter1, ui_Parameter2, ui_Parameter3, ui_Parameter4, ui_Parameter5 };
	lv_obj_t* txt_labels[6] = { ui_ParamTxt, ui_ParamTxt1, ui_ParamTxt2, ui_ParamTxt3, ui_ParamTxt4, ui_ParamTxt5 };
	lv_obj_t* val_labels[6] = { ui_ParamValue, ui_ParamValue1, ui_ParamValue2, ui_ParamValue3, ui_ParamValue4, ui_ParamValue5 };

	for (int i = 0; i < 6; i++) {
		if (lv_strcmp(md->paramNames[i], "--") == 0) {
			lv_obj_add_flag(txt_labels[i], LV_OBJ_FLAG_HIDDEN);
			lv_obj_add_flag(val_labels[i], LV_OBJ_FLAG_HIDDEN);
			lv_obj_add_flag(arcs[i], LV_OBJ_FLAG_HIDDEN);
		}
		else {
			lv_obj_clear_flag(txt_labels[i], LV_OBJ_FLAG_HIDDEN);
			lv_obj_clear_flag(val_labels[i], LV_OBJ_FLAG_HIDDEN);
			lv_label_set_text(txt_labels[i], md->paramNames[i]);

			float current_param_value = active_effect->params[i];

			char valBuf[16];
			lv_snprintf(valBuf, sizeof(valBuf), "%d", (int)current_param_value);
			lv_label_set_text(val_labels[i], valBuf);

			lv_obj_clear_flag(arcs[i], LV_OBJ_FLAG_HIDDEN);
			lv_arc_set_range(arcs[i], md->paramMin[i], md->paramMax[i]);
			lv_arc_set_value(arcs[i], current_param_value);
		}
	}
}

