void ui_UpdatePedalFromDropdown(lv_event_t * e)
{
	// Your code here
	int chosenEffectId = lv_dropdown_get_selected(ui_PedalSel1);
	g_display_mgr.effectsIdx[g_display_mgr.activeSlotIdx] = chosenEffectId;

	AudioChannel_t* active_channel = (g_display_mgr.activeSlotIdx < 5) ? &Channel1 : &Channel2;
	int internal_slot_idx = (g_display_mgr.activeSlotIdx < 5) ? g_display_mgr.activeSlotIdx : g_display_mgr.activeSlotIdx - 5;

	if (chosenEffectId > 0 && chosenEffectId < NUM_EFFECTS) {
		active_channel->chain[internal_slot_idx] = effectList[chosenEffectId];
		active_channel->chain[internal_slot_idx].enabled = true;
		lv_memset(active_channel->chain[internal_slot_idx].state, 0, sizeof(active_channel->chain[internal_slot_idx].state));

		Effect_t* preset_src = (g_display_mgr.activeSlotIdx < 5)
			? &presets[g_display_mgr.PresetIdx].Channel1.chain[internal_slot_idx]
			: &presets[g_display_mgr.PresetIdx].Channel2.chain[internal_slot_idx];

		if (preset_src->process == effectList[chosenEffectId].process) {
			lv_memcpy(active_channel->chain[internal_slot_idx].params, preset_src->params, sizeof(active_channel->chain[internal_slot_idx].params));
		}
	} else {
		active_channel->chain[internal_slot_idx].process = bypassProcess;
		active_channel->chain[internal_slot_idx].enabled = false;
		lv_memset(active_channel->chain[internal_slot_idx].params, 0, sizeof(active_channel->chain[internal_slot_idx].params));
	}

	uiUpdatePedalScreen(e);
}

